{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/Emoklore_Korean.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class Emoklore_Korean < Emoklore\n      # ゲームシステムの識別子\n      ID = \"Emoklore:Korean\"\n\n      # ゲームシステム名\n      NAME = \"에모크로아TRPG\"\n\n      # ゲームシステム名の読みがな\n      #\n      # 「ゲームシステム名の読みがなの設定方法」（docs/dicebot_sort_key.md）を参考にして\n      # 設定してください\n      SORT_KEY = \"国際化:Korean:에모크로아TRPG\"\n\n      # ダイスボットの使い方\n      HELP_MESSAGE = <<~MESSAGETEXT\n        ・기능치 판정（xDM<=y）\n          \"(개수)DM<=(판정치)\"로 판정합니다.\n          주사위의 개수는 생략 가능하며, 생략 시 1개로 설정됩니다.\n          ex）2DM<=5 DM<=8\n\n        ・기능치 판정（sDAa+z)\n          \"(기능 레벨)DA(능력치)+(주사위 보너스)\"로 판정합니다.\n          주사위 보너스의 개수는 생략 가능하며, 생략 시 0개로 설정됩니다.\n          기능 레벨에는 1~3의 수치를 입력합니다. 기본 기능으로 판정하려면 기능 레벨에\"b\"를 입력하세요.\n          주사위 개수는 기능 레벨과 주사위 보너스 개수에 따라 결정되며, s+z개의 주사위를 굴립니다. (s=\"b\"인 경우 s=1)\n          판정치는 s+a 입니다.（s=\"b\"인 경우에는 s=0）\n      MESSAGETEXT\n\n      register_prefix_from_super_class()\n\n      def initialize(command)\n        super(command)\n\n        @locale = :ko_kr\n      end\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:Emoklore_Korean>", "self", "register_prefix_from_super_class", "initialize", "command", "@locale", "Emoklore"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;QAEE,8BAAKA,iBAAL;QAGA,gCAAOA,WAAP;QAMA,oCAAWA,sBAAX;QAGA,wCACNA,mBADqB,GAErBA,+BAFqB,GAGrBA,uCAHqB,GAIrBA,qBAJqB,GAKrBA,IALqB,GAMrBA,mBANqB,GAOrBA,0CAPqB,GAQrBA,2CARqB,GASrBA,+DATqB,GAUrBA,4EAVqB,GAWrBA,sCAXM;QAcAC,IAAAC,kCAAAA,CAAAA;QAEAF,OAAAG,0BAAAA,sBAAeC,OAAfD;AAAAA,UAAAA;;UAAAA;;UACE,OAAAF,IAAA,EAAA,0DAAA,cAAA,EAAA,CAAMG,OAAN,CAAA,EAAA,IAAA;UAEAD,OAAAE,CAAAA,cAAU,OAAVA;QAHFF,CAAAA;MA9BFH,GAAAA,WAAAA,EAAwBM,cAAxBN;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}]}